#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    char buffer[256];
    // consume the newline after T
    fgets(buffer, sizeof(buffer), stdin);
    const char *explanation = "In Python, mutable data types can be changed after creation (e.g., list, dict, set). Immutable data types cannot be changed after creation (e.g., int, float, str, tuple). Example of mutable: lst = [1, 2]; lst.append(3) modifies lst. Example of immutable: s = \"abc\"; trying to assign s[0] = \"d\" raises TypeError.";
    for(int i=0;i<T;i++){
        fgets(buffer, sizeof(buffer), stdin); // read and ignore prompt
        printf("%s", explanation);
        if(i!=T-1) printf("\n");
    }
    return 0;
}

