        String first = br.readLine();
        if(first == null) return;
        int T = Integer.parseInt(first.trim());
        String explanation = "In Python, mutable data types can be changed after creation (e.g., list, dict, set). Immutable data types cannot be changed after creation (e.g., int, float, str, tuple). Example of mutable: lst = [1, 2]; lst.append(3) modifies lst. Example of immutable: s = \"abc\"; trying to assign s[0] = \"d\" raises TypeError.";
        StringBuilder sb = new StringBuilder();
        for(int i=0;i<T;i++){
            br.readLine(); // ignore prompt line
            sb.append(explanation);
            if(i!=T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
